def {{nama_fungsi}}(s):
    """Parse date dari berbagai format."""
    import datetime
    formats = [
        '%Y-%m-%d', '%d/%m/%Y', '%m/%d/%Y', '%d-%m-%Y',
        '%Y/%m/%d', '%d %b %Y', '%d %B %Y', '%b %d, %Y'
    ]
    s = s.strip()
    for fmt in formats:
        try:
            return datetime.datetime.strptime(s, fmt).date()
        except ValueError:
            continue
    raise ValueError(f'Tidak bisa parse tanggal: {s}')

def {{nama_fungsi}}(seconds):
    """Format detik ke human readable ID."""
    seconds = int(seconds)
    parts = []
    h, rem = divmod(seconds, 3600)
    m, s = divmod(rem, 60)
    if h: parts.append(f'{h} jam')
    if m: parts.append(f'{m} menit')
    if s or not parts: parts.append(f'{s} detik')
    return ' '.join(parts)

def {{nama_fungsi}}(d):
    """d: datetime.date atau datetime.datetime"""
    return d.weekday() >= 5

def {{nama_fungsi}}(start, end):
    """Hitung business days. start/end: date."""
    import datetime
    if start > end:
        start, end = end, start
    days = 0
    cur = start
    one_day = datetime.timedelta(days=1)
    while cur <= end:
        if cur.weekday() < 5:
            days += 1
        cur += one_day
    return days

def {{nama_fungsi}}(birth_date, today=None):
    """Hitung umur tahun."""
    import datetime
    if today is None:
        today = datetime.date.today()
    years = today.year - birth_date.year
    if (today.month, today.day) < (birth_date.month, birth_date.day):
        years -= 1
    return years

def {{nama_fungsi}}(dt_obj, from_tz='UTC', to_tz='{{default_tz}}'):
    """Convert timezone aware datetime."""
    try:
        from zoneinfo import ZoneInfo
    except ImportError:
        from backports.zoneinfo import ZoneInfo  # type: ignore
    if dt_obj.tzinfo is None:
        dt_obj = dt_obj.replace(tzinfo=ZoneInfo(from_tz))
    return dt_obj.astimezone(ZoneInfo(to_tz))

def {{nama_fungsi}}(weekday={{weekday}}, hour=9, minute=0, from_dt=None):
    """weekday: 0=Senin ... 6=Minggu. Return datetime berikutnya."""
    import datetime
    if from_dt is None:
        from_dt = datetime.datetime.now()
    days_ahead = (weekday - from_dt.weekday()) % 7
    target = from_dt.replace(hour=hour, minute=minute, second=0, microsecond=0) + datetime.timedelta(days=days_ahead)
    if target <= from_dt:
        target += datetime.timedelta(days=7)
    return target
